 94→export async function runImportJob(id: string) {
 95→  const job = getPersistedImport(id);
 96→  if (!job) {
 97→    return;
 98→  }
 99→
100→  patchJob(id, {
101→    status: "running",
102→    currentStage: "validate",
103→    error: undefined,
104→  });
105→
106→  try {
107→    let timeoutHandle: ReturnType<typeof setTimeout> | undefined;
108→    const timeoutPromise = new Promise<never>((_resolve, reject) => {
109→      timeoutHandle = setTimeout(() => {
110→        reject(
111→          new Error(
112→            `Import timed out after ${IMPORT_TIMEOUT_MS / 1_000}s waiting for the share page to load.`,
113→          ),
114→        );
115→      }, IMPORT_TIMEOUT_MS);
116→    });
117→
118→    let imported: Awaited<ReturnType<typeof importSharePage>> | undefined;
119→    try {
120→      imported = await Promise.race([
121→        importSharePage(job.sourceUrl, {
122→          sourcePlatform: job.sourcePlatform,
123→          onStage: (stage) => {
124→            patchJob(id, {
125→              currentStage: stage,
126→            });
127→          },
128→        }),
129→        timeoutPromise,
130→      ]);
131→    } finally {
132→      clearTimeout(timeoutHandle);
133→    }
134→
135→    withTransaction(() => {
136→      patchJob(id, {
137→        currentStage: "render",
138→        conversation: imported.conversation,
139→        summary: {
140→          messageCount: imported.conversation.messages.length,
141→          transcriptWords: conversationWordCount(imported.conversation),
142→        },
143→        warnings: imported.warnings,
144→      });
145→
146→      saveImportSnapshot({
147→        importId: id,
148→        sourceUrl: job.sourceUrl,
149→        finalUrl: imported.snapshot.finalUrl,
150→        fetchedAt: imported.snapshot.fetchedAt,
151→        pageTitle: imported.snapshot.pageTitle,
152→        rawHtml: imported.snapshot.rawHtml,
153→        normalizedPayload: imported.snapshot.normalizedPayload,
154→        fetchMetadata: imported.snapshot.fetchMetadata,
155→      });
156→
157→      const rendered = getImportJob(id);
158→      if (!rendered) {
159→        return;
160→      }
161→
162→      patchJob(id, {
163→        status: "completed",
164→        currentStage: "done",
165→        artifacts: buildArtifacts(rendered),
166→      });
167→    });
168→  } catch (error) {
169→    const currentJob = getPersistedImport(id);
170→    patchJob(id, {
171→      status: "failed",
172→      errorStage: currentJob?.currentStage,
173→      currentStage: "done",
174→      error:
175→        error instanceof Error
176→          ? error.message
177→          : "Die Import-Pipeline ist fehlgeschlagen.",
178→    });
179→  }
180→}
