 85→export function FormatWorkspace({
 86→  activeStage,
 87→  elapsedTime,
 88→  job,
 89→  view,
 90→  onViewChange,
 91→}: FormatWorkspaceProps) {
 92→  const isAdjustableView = adjustableViews.has(view);
 93→
 94→  const session = useAdjustmentSession(view, job.id);
 95→  const rules = useFormatRules(view, job.id);
 96→  const snapshots = useSnapshots(job.id);
 97→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 98→  const resolvedMessages = useResolvedConversation(
 99→    job.conversation,
100→    messageEdits.editedMessagesMap,
101→  );
102→  const autoSnapshot = useAutoSnapshot({
103→    activeSnapshot: snapshots.activeSnapshot,
104→    create: snapshots.create,
105→    activate: snapshots.activate,
106→  });
107→  const deletion = useMessageDeletion(job.id);
108→  const deletionToast = useDeletionToast();
109→  const [editMode, setEditMode] = useState<EditMode>("view");
110→
111→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
112→  const handleEditModeChange = useCallback(
113→    (mode: EditMode) => {
114→      if (mode === "edit" && session.adjustModeEnabled) {
115→        session.toggleAdjustMode();
116→      }
117→      setEditMode(mode);
118→    },
119→    [session],
120→  );
121→
122→  const handleToggleAdjustMode = useCallback(() => {
123→    if (!session.adjustModeEnabled && editMode === "edit") {
124→      setEditMode("view");
125→    }
126→    session.toggleAdjustMode();
127→  }, [session, editMode]);
128→
129→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
130→
131→  // beforeunload warning when unsaved edits exist.
132→  // hasPendingEdits covers both debounce timers that haven't fired yet and
133→  // in-flight HTTP mutations, preventing data loss during the 500 ms debounce
134→  // window where isSaving alone would still be false.
135→  useEffect(() => {
136→    if (!messageEdits.hasPendingEdits) return;
137→    const handler = (e: BeforeUnloadEvent) => {
138→      e.preventDefault();
139→    };
140→    window.addEventListener("beforeunload", handler);
141→    return () => window.removeEventListener("beforeunload", handler);
142→  }, [messageEdits.hasPendingEdits]);
143→
144→  const handleBlocksChange = useCallback(
145→    (messageId: string, blocks: Block[]) => {
146→      void autoSnapshot.ensureSnapshot().then((ready) => {
147→        if (ready) {
148→          messageEdits.saveEdit(messageId, blocks);
149→        }
150→      });
151→    },
152→    [autoSnapshot, messageEdits],
153→  );
154→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
155→  const [deleteDialog, setDeleteDialog] = useState<{
156→    messageId: string;
157→    isRound: boolean;
158→    preview: string;
159→  } | null>(null);
160→  const popover = useAdjustmentPopover();
161→
162→  const handleDeleteMessage = useCallback(
163→    (messageId: string) => {
164→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
165→      const preview =
166→        msg?.blocks
167→          .map((b) => ("text" in b ? b.text : b.type))
168→          .join(" ")
169→          .slice(0, 200) ?? messageId;
170→      setDeleteDialog({ messageId, isRound: false, preview });
171→    },
172→    [job.conversation?.messages],
173→  );
174→
175→  const handleDeleteRound = useCallback(
176→    (messageId: string) => {
177→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
178→      const preview =
179→        msg?.blocks
180→          .map((b) => ("text" in b ? b.text : b.type))
181→          .join(" ")
182→          .slice(0, 200) ?? messageId;
183→      setDeleteDialog({ messageId, isRound: true, preview });
184→    },
185→    [job.conversation?.messages],
186→  );
187→
188→  const handleConfirmDelete = useCallback(
189→    async (reason?: string) => {
190→      if (!deleteDialog) return;
191→      const { messageId, isRound } = deleteDialog;
192→      setDeleteDialog(null);
193→      if (isRound) {
194→        const result = await deletion.deleteRound(messageId, reason);
195→        deletionToast.showDeletedToast(messageId, true, result.length);
196→      } else {
197→        await deletion.deleteMessage(messageId, reason);
198→        deletionToast.showDeletedToast(messageId, false);
199→      }
200→    },
201→    [deleteDialog, deletion, deletionToast],
202→  );
203→
204→  const handleUndoDelete = useCallback(async () => {
205→    if (!deletionToast.toast) return;
206→    await deletion.restoreMessage(deletionToast.toast.messageId);
207→    deletionToast.dismissToast();
208→  }, [deletion, deletionToast]);
209→
210→  const mergedRef = useCallback(
211→    (node: HTMLElement | null) => {
212→      (
213→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
214→      ).current = node;
215→      (
216→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
217→      ).current = node;
218→    },
219→    [session.sectionRef, popover.containerRef],
220→  );
221→
222→  const artifact = view === "reader" ? "" : renderArtifact(view, job);
223→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
224→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
225→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
226→  const displayedMarkdown = useMemo(() => {
227→    if (view !== "markdown") return artifact;
228→    try {
229→      return applyMarkdownRules(artifact, rules.activeRules);
230→    } catch {
231→      return artifact;
232→    }
233→  }, [artifact, rules.activeRules, view]);
234→
235→  const resolvedConversation = useMemo(() => {
236→    if (!job.conversation) return undefined;
237→    return {
238→      ...job.conversation,
239→      messages: resolvedMessages.map((rm) => ({
240→        id: rm.id,
241→        role: rm.role,
242→        blocks: rm.blocks,
243→      })),
244→    };
245→  }, [job.conversation, resolvedMessages]);
246→
247→  const readerEffectsMap = useMemo(
248→    () =>
249→      view === "reader" && resolvedConversation
250→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
251→        : new Map(),
252→    [rules.activeRules, resolvedConversation, view],
253→  );
254→
255→  const handleCopyMessage = useCallback(
256→    (messageId: string) => {
257→      const msg = resolvedConversation?.messages.find(
258→        (m) => m.id === messageId,
259→      );
260→      if (!msg) return;
261→      void copyMessageToClipboard(msg, view, msg.blocks);
262→    },
263→    [resolvedConversation, view],
264→  );
265→
266→  const [copySuccess, setCopySuccess] = useState(false);
267→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
268→
269→  const handleCopyAll = useMemo(() => {
270→    const doCopy = async (content: string, isHtml: boolean) => {
271→      try {
272→        if (isHtml) {
273→          const blob = new Blob([content], { type: "text/html" });
274→          const plainBlob = new Blob([content], { type: "text/plain" });
275→          await navigator.clipboard.write([
276→            new ClipboardItem({
277→              "text/html": blob,
278→              "text/plain": plainBlob,
279→            }),
280→          ]);
281→        } else {
282→          await navigator.clipboard.writeText(content);
283→        }
284→        clearTimeout(copyTimeoutRef.current);
285→        setCopySuccess(true);
286→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
287→      } catch {
288→        // Fallback: silently fail
289→      }
290→    };
291→
292→    if (view === "markdown") {
293→      return () => {
294→        void doCopy(displayedMarkdown, false);
295→      };
296→    }
297→    if (view === "reader" && resolvedConversation) {
298→      return () => {
299→        const html = buildReaderHtml(
300→          resolvedConversation,
301→          readerEffectsMap,
302→          resolvedConversation.title ?? `export-${job.id}`,
303→        );
304→        void doCopy(html, true);
305→      };
306→    }
307→    if ((view === "handover" || view === "json") && artifact) {
308→      return () => {
309→        void doCopy(artifact, false);
310→      };
311→    }
312→    return undefined;
313→  }, [
314→    view,
315→    displayedMarkdown,
316→    job.id,
317→    resolvedConversation,
318→    readerEffectsMap,
319→    artifact,
320→  ]);
321→
322→  const handleDownload = useMemo(() => {
323→    if (view === "markdown") {
