 26→export function resolveReaderBlockEffects(
 27→  rules: FormatRule[],
 28→  messageId: string,
 29→  blockIndex: number,
 30→  blockType: Block["type"],
 31→  blockText: string,
 32→  context?: ReaderMatchContext,
 33→) {
 34→  return rules
 35→    .filter(
 36→      (rule) =>
 37→        rule.status === "active" &&
 38→        matchesReaderRule(
 39→          rule,
 40→          messageId,
 41→          blockIndex,
 42→          blockType,
 43→          blockText,
 44→          context,
 45→        ),
 46→    )
 47→    .map((rule) => rule.compiledRule)
 48→    .filter((effect): effect is RuleEffect => effect !== undefined)
 49→    .map(normalizeLegacyEffect);
 50→}
 51→
 52→export function buildReaderEffectsMap(
 53→  rules: FormatRule[],
 54→  conversation: Conversation,
 55→): Map<string, RuleEffect[]> {
 56→  const activeRules = rules.filter((r) => r.status === "active");
 57→  const effectsMap = new Map<string, RuleEffect[]>();
 58→
 59→  for (const message of conversation.messages) {
 60→    const context: ReaderMatchContext = {
 61→      messageRole: message.role,
 62→      blocks: message.blocks,
 63→    };
 64→
 65→    for (
 66→      let blockIndex = 0;
 67→      blockIndex < message.blocks.length;
 68→      blockIndex += 1
 69→    ) {
 70→      const block = message.blocks[blockIndex];
 71→
 72→      if (!block) {
 73→        continue;
 74→      }
 75→
 76→      const effects = activeRules
 77→        .filter((rule) =>
 78→          matchesReaderRule(
 79→            rule,
 80→            message.id,
 81→            blockIndex,
 82→            block.type,
 83→            blockToPlainText(block),
 84→            context,
 85→          ),
 86→        )
 87→        .map((rule) => rule.compiledRule)
 88→        .filter((effect): effect is RuleEffect => effect !== undefined)
 89→        .map(normalizeLegacyEffect);
 90→
 91→      if (effects.length > 0) {
 92→        effectsMap.set(`${message.id}:${blockIndex}`, effects);
 93→      }
 94→    }
 95→  }
 96→
 97→  return effectsMap;
 98→}
 99→
100→export function applyMarkdownRules(content: string, rules: FormatRule[]) {
101→  const lines = content.split("\n");
102→  const nextLines = [...lines];
103→
104→  for (const rule of rules) {
105→    if (rule.status !== "active") {
106→      continue;
107→    }
108→
109→    const parsedSelector = ruleSelectorSchema.safeParse(rule.selector);
110→    const parsedEffect = ruleEffectSchema.safeParse(rule.compiledRule);
111→
112→    if (!parsedSelector.success || !parsedEffect.success) {
113→      continue;
114→    }
115→
116→    const selector = parsedSelector.data;
117→    const effect = normalizeLegacyEffect(parsedEffect.data);
118→
119→    const strategy = "strategy" in selector ? selector.strategy : undefined;
120→
121→    if (strategy === "compound") {
122→      const transform = effect.markdownTransform;
123→      if (!transform) continue;
124→
125→      // Compound in Markdown: textPattern match on each line
126→      // blockType/messageRole/context not relevant for Markdown (line-based only)
127→      const textPattern =
128→        "textPattern" in selector ? selector.textPattern : null;
129→
130→      for (let index = 0; index < nextLines.length; index += 1) {
131→        const line = nextLines[index] ?? "";
132→
133→        // If textPattern set: only transform matching lines
134→        if (textPattern) {
135→          try {
136→            if (!new RegExp(textPattern).test(line)) continue;
137→          } catch {
138→            continue;
139→          }
140→        }
141→
142→        // Apply transform (same switch logic as for exact)
143→        switch (transform) {
144→          case "promote_to_heading":
145→            nextLines[index] = `## ${line.replace(/^#+\s*/, "")}`.trimEnd();
146→            break;
147→          case "bold_prefix_before_colon":
148→            nextLines[index] = line.replace(
149→              /^([^:\n]{1,120}:)(?!\*)/,
150→              "**$1**",
151→            );
152→            break;
153→          case "normalize_list_structure": {
154→            const trimmedLine = line.trim();
155→            if (!trimmedLine) break;
156→            nextLines[index] = /^[-*]\s/.test(trimmedLine)
157→              ? trimmedLine
158→              : `- ${trimmedLine}`;
159→            break;
160→          }
161→          case "normalize_markdown_table":
162→            if (line.includes("|")) {
163→              nextLines[index] = line
164→                .split("|")
165→                .map((cell) => cell.trim())
166→                .join(" | ")
167→                .trim();
168→            }
169→            break;
170→          case "reshape_markdown_block":
171→            nextLines[index] = line.trimEnd();
172→            break;
173→        }
174→      }
175→      continue;
176→    }
177→
178→    // All effects are now custom_style after normalization
179→    {
180→      const transform = effect.markdownTransform;
181→      if (!transform) continue;
182→
183→      if (
184→        strategy === "prefix_before_colon" &&
185→        transform === "bold_prefix_before_colon"
186→      ) {
187→        for (let index = 0; index < nextLines.length; index += 1) {
188→          const line = nextLines[index] ?? "";
189→          nextLines[index] = line.replace(/^([^:\n]{1,120}:)(?!\*)/, "**$1**");
190→        }
191→        continue;
192→      }
193→
194→      if (
195→        strategy === "markdown_table" &&
196→        transform === "normalize_markdown_table"
197→      ) {
198→        for (let index = 0; index < nextLines.length; index += 1) {
199→          const line = nextLines[index] ?? "";
200→          if (!line.includes("|")) continue;
201→          nextLines[index] = line
202→            .split("|")
203→            .map((cell) => cell.trim())
204→            .join(" | ")
205→            .trim();
206→        }
207→        continue;
208→      }
209→
210→      const lineStart = "lineStart" in selector ? selector.lineStart : null;
211→      const lineEnd = "lineEnd" in selector ? selector.lineEnd : lineStart;
212→      if (!lineStart || !lineEnd) continue;
213→      const startIndex = Math.max(0, lineStart - 1);
214→      const endIndex = Math.min(nextLines.length - 1, lineEnd - 1);
215→
216→      switch (transform) {
217→        case "promote_to_heading":
218→          nextLines[startIndex] =
219→            `## ${nextLines[startIndex]?.replace(/^#+\s*/, "") ?? ""}`.trimEnd();
220→          break;
221→        case "bold_prefix_before_colon":
222→          for (let index = startIndex; index <= endIndex; index += 1) {
223→            const line = nextLines[index] ?? "";
224→            nextLines[index] = line.replace(
225→              /^([^:\n]{1,120}:)(?!\*)/,
226→              "**$1**",
227→            );
228→          }
229→          break;
230→        case "normalize_list_structure":
231→          for (let index = startIndex; index <= endIndex; index += 1) {
232→            const line = nextLines[index] ?? "";
233→            const trimmedLine = line.trim();
234→            if (!trimmedLine) continue;
235→            nextLines[index] = /^[-*]\s/.test(trimmedLine)
236→              ? trimmedLine
237→              : `- ${trimmedLine}`;
238→          }
239→          break;
240→        case "normalize_markdown_table":
241→          for (let index = startIndex; index <= endIndex; index += 1) {
242→            const line = nextLines[index] ?? "";
243→            nextLines[index] = line
244→              .split("|")
245→              .map((cell) => cell.trim())
246→              .join(" | ")
247→              .trim();
248→          }
249→          break;
250→        case "reshape_markdown_block":
251→          for (let index = startIndex; index <= endIndex; index += 1) {
252→            nextLines[index] = (nextLines[index] ?? "").trimEnd();
253→          }
254→          break;
255→      }
256→    }
257→  }
258→
259→  return nextLines.join("\n");
260→}
