  1→import type {
  2→  Block,
  3→  CompoundContextSibling,
  4→  CompoundSelector,
  5→  Conversation,
  6→  FormatRule,
  7→} from "@chat-exporter/shared";
  8→import { ruleSelectorSchema } from "@chat-exporter/shared";
  9→
 10→import { blockToPlainText } from "./reader-block-render";
 11→
 12→export type ReaderMatchContext = {
 13→  messageRole: string;
 14→  blocks: Block[];
 15→};
 16→
 17→export function matchesReaderRule(
 18→  rule: FormatRule,
 19→  messageId: string,
 20→  blockIndex: number,
 21→  blockType: Block["type"],
 22→  blockText: string,
 23→  context?: ReaderMatchContext,
 24→) {
 25→  const parsed = ruleSelectorSchema.safeParse(rule.selector);
 26→
 27→  if (!parsed.success) {
 28→    return false;
 29→  }
 30→
 31→  const selector = parsed.data;
 32→
 33→  if ("strategy" in selector && selector.strategy === "compound") {
 34→    return matchesCompoundSelector(
 35→      selector,
 36→      blockType,
 37→      blockText,
 38→      blockIndex,
 39→      context,
 40→    );
 41→  }
 42→
 43→  if ("strategy" in selector && selector.strategy === "block_type") {
 44→    return selector.blockType === blockType;
 45→  }
 46→
 47→  if ("strategy" in selector && selector.strategy === "prefix_before_colon") {
 48→    return (
 49→      "blockType" in selector &&
 50→      selector.blockType === blockType &&
 51→      /^([^:\n]{1,120}:)(\s*)(.*)$/.test(blockText)
 52→    );
 53→  }
 54→
 55→  // exact match (strategy === "exact")
 56→  return (
 57→    "messageId" in selector &&
 58→    selector.messageId === messageId &&
 59→    "blockIndex" in selector &&
 60→    selector.blockIndex === blockIndex &&
 61→    "blockType" in selector &&
 62→    selector.blockType === blockType
 63→  );
 64→}
 65→
 66→function matchesCompoundSelector(
 67→  selector: CompoundSelector,
 68→  blockType: Block["type"],
 69→  blockText: string,
 70→  blockIndex: number,
 71→  context?: ReaderMatchContext,
 72→): boolean {
 73→  if (selector.blockType !== undefined && selector.blockType !== blockType) {
 74→    return false;
 75→  }
 76→
 77→  if (selector.messageRole !== undefined) {
 78→    if (context === undefined || selector.messageRole !== context.messageRole) {
 79→      return false;
 80→    }
 81→  }
 82→
 83→  if (selector.headingLevel !== undefined) {
 84→    if (blockType !== "heading") {
 85→      return false;
 86→    }
 87→    if (context !== undefined) {
 88→      const block = context.blocks[blockIndex];
 89→      if (
 90→        block === undefined ||
 91→        block.type !== "heading" ||
 92→        block.level !== selector.headingLevel
 93→      ) {
 94→        return false;
 95→      }
 96→    }
 97→  }
 98→
 99→  if (selector.position !== undefined && context !== undefined) {
100→    if (selector.position === "first" && blockIndex !== 0) {
101→      return false;
102→    }
103→    if (
104→      selector.position === "last" &&
105→      blockIndex !== context.blocks.length - 1
106→    ) {
107→      return false;
108→    }
109→  }
110→
111→  if (selector.textPattern !== undefined) {
112→    if (!matchesTextPattern(blockText, selector.textPattern)) {
113→      return false;
114→    }
115→  }
116→
117→  if (selector.context !== undefined && context !== undefined) {
118→    if (selector.context.previousSibling !== undefined) {
119→      const prevBlock = context.blocks[blockIndex - 1];
120→      if (!matchesSiblingFilter(prevBlock, selector.context.previousSibling)) {
121→        return false;
122→      }
123→    }
124→
125→    if (selector.context.nextSibling !== undefined) {
126→      const nextBlock = context.blocks[blockIndex + 1];
127→      if (!matchesSiblingFilter(nextBlock, selector.context.nextSibling)) {
128→        return false;
129→      }
130→    }
131→  }
132→
133→  return true;
134→}
135→
136→function matchesTextPattern(text: string, pattern: string): boolean {
137→  try {
138→    return new RegExp(pattern).test(text);
139→  } catch {
140→    return false;
141→  }
142→}
143→
144→function matchesSiblingFilter(
145→  block: Block | undefined,
146→  filter: CompoundContextSibling,
147→): boolean {
148→  if (block === undefined) {
149→    return false;
150→  }
151→
152→  if (filter.blockType !== undefined && block.type !== filter.blockType) {
153→    return false;
154→  }
155→
156→  if (filter.headingLevel !== undefined) {
157→    if (block.type !== "heading" || block.level !== filter.headingLevel) {
158→      return false;
159→    }
160→  }
161→
162→  if (filter.textPattern !== undefined) {
163→    const text =
164→      block.type === "list"
165→        ? block.items.join("\n")
166→        : block.type === "table"
167→          ? [
168→              block.headers.join(" | "),
169→              ...block.rows.map((row) => row.join(" | ")),
170→            ].join("\n")
171→          : block.text;
172→
173→    if (!matchesTextPattern(text, filter.textPattern)) {
174→      return false;
175→    }
176→  }
177→
178→  return true;
179→}
