181→export function getBlocksMatchingRule(
182→  rule: FormatRule,
183→  conversation: Conversation,
184→): Array<{ messageId: string; blockIndex: number }> {
185→  const matches: Array<{ messageId: string; blockIndex: number }> = [];
186→
187→  for (const message of conversation.messages) {
188→    const context: ReaderMatchContext = {
189→      messageRole: message.role,
190→      blocks: message.blocks,
191→    };
192→
193→    for (
194→      let blockIndex = 0;
195→      blockIndex < message.blocks.length;
196→      blockIndex += 1
197→    ) {
198→      const block = message.blocks[blockIndex];
199→
200→      if (!block) {
201→        continue;
202→      }
203→
204→      if (
205→        matchesReaderRule(
206→          rule,
207→          message.id,
208→          blockIndex,
209→          block.type,
210→          blockToPlainText(block),
211→          context,
212→        )
213→      ) {
214→        matches.push({ messageId: message.id, blockIndex });
215→      }
216→    }
217→  }
218→
219→  return matches;
220→}
