 10→function escapeHtml(text: string): string {
 11→  return text
 12→    .replace(/&/g, "&amp;")
 13→    .replace(/</g, "&lt;")
 14→    .replace(/>/g, "&gt;")
 15→    .replace(/"/g, "&quot;");
 16→}
 17→
 18→function renderMarkdownStrong(text: string): string {
 19→  return escapeHtml(text).replace(
 20→    /\*\*([^*\n][^*\n]*)\*\*/g,
 21→    "<strong>$1</strong>",
 22→  );
 23→}
 24→
 25→function renderBlockHtml(block: Block): string {
 26→  switch (block.type) {
 27→    case "paragraph": {
 28→      const numberedBoldMatch = block.text.match(
 29→        /^\*\*(\d+\.\s.+?)\*\*\s*([\s\S]*)$/,
 30→      );
 31→      if (numberedBoldMatch) {
 32→        const heading = escapeHtml(numberedBoldMatch[1] ?? "");
 33→        const rest = numberedBoldMatch[2]?.trim();
 34→        let html = `<hr class="block-hr"><h2 class="block-heading">${heading}</h2>`;
 35→        if (rest) {
 36→          html += `<p class="block-paragraph">${renderMarkdownStrong(rest)}</p>`;
 37→        }
 38→        return html;
 39→      }
 40→      return `<p class="block-paragraph">${renderMarkdownStrong(block.text)}</p>`;
 41→    }
 42→    case "heading": {
 43→      const level = Math.min(block.level, 6);
 44→      return `<h${level} class="block-heading">${renderMarkdownStrong(block.text)}</h${level}>`;
 45→    }
 46→    case "list":
 47→      return `<ul class="block-list">${block.items.map((item) => `<li>${renderMarkdownStrong(item)}</li>`).join("")}</ul>`;
 48→    case "quote":
 49→      return `<blockquote class="block-quote">${renderMarkdownStrong(block.text)}</blockquote>`;
 50→    case "code":
 51→      return `<div class="block-code">${block.language ? `<p class="code-lang">${escapeHtml(block.language)}</p>` : ""}<pre><code>${escapeHtml(block.text)}</code></pre></div>`;
 52→    case "table":
 53→      return `<div class="block-table-wrap"><table class="block-table"><thead><tr>${block.headers.map((h) => `<th>${escapeHtml(h)}</th>`).join("")}</tr></thead><tbody>${block.rows.map((row) => `<tr>${row.map((cell) => `<td>${escapeHtml(cell)}</td>`).join("")}</tr>`).join("")}</tbody></table></div>`;
 54→  }
 55→}
 56→
 57→function renderMessageHtml(
 58→  message: Conversation["messages"][number],
 59→  index: number,
 60→  effectsMap: Map<string, RuleEffect[]>,
 61→): string {
 62→  const roleClass = message.role === "assistant" ? "msg-assistant" : "msg-user";
 63→  const roleLabel = ROLE_LABELS[message.role] ?? message.role;
 64→
 65→  const blocksHtml = message.blocks
 66→    .map((block, blockIndex) => {
 67→      const effects = effectsMap.get(`${message.id}:${blockIndex}`) ?? [];
 68→      const style = collectContainerStyle(effects);
 69→      const styleAttr = style ? ` style="${style}"` : "";
 70→      return `<div class="block-wrapper"${styleAttr}>${renderBlockHtml(block)}</div>`;
 71→    })
 72→    .join("\n");
 73→
 74→  return `<article class="message ${roleClass}">
 75→  <div class="msg-header">
 76→    <span>${escapeHtml(roleLabel)}</span>
 77→    <span>${index + 1}</span>
 78→  </div>
 79→  <div class="msg-blocks">
 80→${blocksHtml}
 81→  </div>
 82→</article>`;
 83→}
 84→
 85→function collectContainerStyle(effects: RuleEffect[]): string {
 86→  const styles: Record<string, string> = {};
 87→  for (const effect of effects) {
 88→    if (effect.type !== "custom_style") continue;
 89→    if (effect.containerStyle) Object.assign(styles, effect.containerStyle);
 90→  }
 91→  return escapeHtml(
 92→    Object.entries(styles)
 93→      .map(([k, v]) => `${camelToKebab(k)}: ${v}`)
 94→      .join("; "),
 95→  );
 96→}
 97→
 98→function camelToKebab(str: string): string {
 99→  return str.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`);
100→}
